#!/usr/bin/env node
// Loads seed/dev-seed.sql into an already-migrated Supabase/Postgres DB, then
// resets every identity sequence so the next autogenerated id continues past the
// seed's explicit ids. The comment-strip + ';'-split is the exact pattern
// test/e2e/setup.ts uses to load the same seed on D1, so both backends stay in
// lockstep. Usage: SUPABASE_DB_URL=postgres://... node scripts/db/seed-supabase.mjs
import { readFileSync } from 'node:fs';
import postgres from 'postgres';

const url = process.env.SUPABASE_DB_URL ?? process.env.DATABASE_URL;
if (!url) {
  console.error('set SUPABASE_DB_URL (or DATABASE_URL)');
  process.exit(1);
}

// Copied verbatim from test/e2e/setup.ts: drop full-line `--` comments, rejoin,
// split on the statement terminator, trim, and drop empties.
function seedStatements(sql) {
  return sql
    .split('\n')
    .filter((line) => !line.trimStart().startsWith('--'))
    .join('\n')
    .split(';')
    .map((s) => s.trim())
    .filter((s) => s.length > 0);
}

const sql = postgres(url, { max: 1, fetch_types: false, onnotice: () => {} });
try {
  const statements = seedStatements(readFileSync('seed/dev-seed.sql', 'utf8'));
  await sql.begin(async (tx) => {
    for (const statement of statements) {
      await tx.unsafe(statement);
    }
    // The seed inserts explicit ids, which never advances the identity
    // sequences. Bump each `id` identity sequence past the seeded max so a later
    // autogenerated insert can't collide with a seeded row.
    const idTables = await tx.unsafe(
      "SELECT table_name FROM information_schema.columns WHERE column_name = 'id' AND is_identity = 'YES' AND table_schema = 'public'",
    );
    for (const { table_name } of idTables) {
      await tx.unsafe(
        `SELECT setval(pg_get_serial_sequence('${table_name}', 'id'), (SELECT coalesce(max(id), 1) FROM "${table_name}"))`,
      );
    }
  });
  console.log(`seeded ${statements.length} statements`);
} catch (err) {
  console.error(err);
  process.exitCode = 1;
} finally {
  await sql.end();
}
